const QUESTIONS: Q[] = [
  { question: "Milliampere-seconds (mAs) controls:", optionA: "Beam quality (penetrating ability)", optionB: "Beam quantity (number of photons)", optionC: "Beam energy spectrum", optionD: "Focal spot size", correctAnswer: "B", rationale: "mAs controls the quantity of X-ray photons produced. Doubling mAs doubles the number of photons and the radiation output.", category: "Image Production", topic: "Technical Factors", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "kVp controls:", optionA: "Beam quantity only", optionB: "Beam quality (penetrating ability) and contrast", optionC: "Focal spot size", optionD: "Exposure time only", correctAnswer: "B", rationale: "kVp controls beam quality (energy/penetrating ability). Higher kVp produces a more penetrating beam with lower contrast and vice versa.", category: "Image Production", topic: "Technical Factors", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "The 15% rule states that increasing kVp by 15%:", optionA: "Halves the density", optionB: "Has the same effect as doubling the mAs on receptor exposure", optionC: "Has no effect on image density", optionD: "Reduces patient dose", correctAnswer: "B", rationale: "Increasing kVp by 15% approximately doubles the exposure to the receptor, equivalent to doubling the mAs.", category: "Image Production", topic: "Technical Factors", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "If the original technique is 10 mAs at 80 kVp and you increase to 92 kVp (15% increase), to maintain density you should:", optionA: "Double the mAs to 20", optionB: "Halve the mAs to 5", optionC: "Keep mAs the same", optionD: "Triple the mAs", correctAnswer: "B", rationale: "A 15% increase in kVp doubles exposure, so mAs should be halved (from 10 to 5 mAs) to maintain the same receptor exposure.", category: "Image Production", topic: "Technical Factors", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Spatial resolution in radiography is measured in:", optionA: "Sieverts", optionB: "Line pairs per millimeter (lp/mm)", optionC: "Hounsfield units", optionD: "Pixels per inch", correctAnswer: "B", rationale: "Spatial resolution is measured in line pairs per millimeter (lp/mm). Higher values indicate better ability to distinguish fine detail.", category: "Image Production", topic: "Image Quality", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "The primary controlling factor for radiographic contrast is:", optionA: "mAs", optionB: "kVp", optionC: "SID", optionD: "Focal spot size", correctAnswer: "B", rationale: "kVp is the primary controlling factor for contrast. Lower kVp produces higher contrast (more photoelectric effect); higher kVp produces lower contrast (more Compton scatter).", category: "Image Production", topic: "Image Quality", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "Increasing kVp results in:", optionA: "Higher contrast (short-scale)", optionB: "Lower contrast (long-scale) with more gray shades", optionC: "No change in contrast", optionD: "Better spatial resolution", correctAnswer: "B", rationale: "Higher kVp increases Compton scattering and reduces photoelectric absorption, producing more shades of gray (long-scale/low contrast).", category: "Image Production", topic: "Image Quality", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "High contrast (short-scale contrast) is best for imaging:", optionA: "Soft tissue structures", optionB: "Bones and chest", optionC: "Abdomen", optionD: "Barium-filled structures", correctAnswer: "B", rationale: "High contrast (short-scale) with fewer gray shades is ideal for bony structures. Low kVp enhances the photoelectric effect, producing high contrast.", category: "Image Production", topic: "Image Quality", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "The primary factor controlling radiographic density/brightness is:", optionA: "kVp", optionB: "mAs", optionC: "SID", optionD: "Focal spot size", correctAnswer: "B", rationale: "mAs is the primary controlling factor for image density/brightness. It directly controls the number of photons reaching the image receptor.", category: "Image Production", topic: "Image Quality", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "Object unsharpness (geometric blur) is minimized by:", optionA: "Using a large focal spot", optionB: "Using a small focal spot, long SID, and short OID", optionC: "Using short SID", optionD: "Using large OID", correctAnswer: "B", rationale: "Geometric unsharpness is minimized by small focal spot (sharper penumbra), long SID (more parallel beam), and short OID (less magnification).", category: "Image Production", topic: "Image Quality", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Magnification in radiography is calculated as:", optionA: "SID / SOD", optionB: "SOD / SID", optionC: "SID / OID", optionD: "OID / SOD", correctAnswer: "A", rationale: "Magnification factor = SID / SOD (source-to-object distance). MF can also be expressed as (SID) / (SID - OID).", category: "Image Production", topic: "Image Quality", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "If the SID is changed from 40 inches to 72 inches, the mAs must be adjusted by what factor to maintain density?", optionA: "Multiply by 1.8", optionB: "Multiply by 3.24", optionC: "Divide by 3.24", optionD: "No change needed", correctAnswer: "B", rationale: "Using the density maintenance formula (direct square law): new mAs = old mAs × (new SID / old SID)² = old mAs × (72/40)² = old mAs × 3.24.", category: "Image Production", topic: "Technical Factors", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "The anode heel effect causes:", optionA: "Uniform beam intensity", optionB: "Greater intensity on the cathode side of the beam", optionC: "Greater intensity on the anode side", optionD: "Increased penumbra on the anode side", correctAnswer: "B", rationale: "The anode heel effect produces greater beam intensity on the cathode side because photons produced deep in the anode are absorbed by the target material on the anode side.", category: "Image Production", topic: "X-ray Beam Characteristics", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "For proper use of the anode heel effect when imaging a structure with varying thickness, the thicker portion should be placed toward the:", optionA: "Anode side", optionB: "Cathode side", optionC: "Center of the beam", optionD: "Edge of the field", correctAnswer: "B", rationale: "The thicker body part should be placed toward the cathode (higher intensity) end, and the thinner part toward the anode (lower intensity) end for more uniform density.", category: "Image Production", topic: "X-ray Beam Characteristics", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "In computed radiography (CR), the latent image is stored on:", optionA: "A film emulsion", optionB: "A photostimulable phosphor (PSP) plate", optionC: "An amorphous selenium detector", optionD: "A CCD chip", correctAnswer: "B", rationale: "CR uses a photostimulable phosphor (PSP) plate (typically barium fluorohalide activated with europium) that stores the latent image as trapped electrons.", category: "Image Production", topic: "Digital Imaging", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "In CR, the latent image is read out by:", optionA: "Heating the plate", optionB: "Stimulating with a helium-neon laser beam", optionC: "Chemical processing", optionD: "Light exposure", correctAnswer: "B", rationale: "During readout, a helium-neon laser scans the PSP plate, stimulating trapped electrons to release stored energy as light (photostimulated luminescence), which is detected by a PMT.", category: "Image Production", topic: "Digital Imaging", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Direct-conversion digital radiography detectors use:", optionA: "Cesium iodide scintillator", optionB: "Amorphous selenium (a-Se)", optionC: "Photostimulable phosphor", optionD: "Gadolinium oxysulfide", correctAnswer: "B", rationale: "Direct-conversion DR uses amorphous selenium to directly convert X-ray photons into electrical signals without an intermediate light-conversion step.", category: "Image Production", topic: "Digital Imaging", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Indirect-conversion digital radiography detectors use:", optionA: "Amorphous selenium", optionB: "A scintillator (CsI or GOS) coupled with a-Si photodiode array", optionC: "Photostimulable phosphor", optionD: "Film-screen combination", correctAnswer: "B", rationale: "Indirect DR uses a scintillator (cesium iodide or gadolinium oxysulfide) to convert X-rays to light, then an amorphous silicon (a-Si) photodiode array to convert light to electrical signal.", category: "Image Production", topic: "Digital Imaging", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Detective quantum efficiency (DQE) measures:", optionA: "Spatial resolution", optionB: "The efficiency of converting incident X-rays into a useful image signal", optionC: "Contrast resolution only", optionD: "Exposure latitude", correctAnswer: "B", rationale: "DQE measures the overall efficiency of a detector in converting incident X-ray photons into a useful diagnostic image signal. Higher DQE means better image quality per dose.", category: "Image Production", topic: "Digital Imaging", difficulty: 3, country: "usa", exam: "arrt" },
  { question: "Which detector type generally has the highest DQE?", optionA: "CR (computed radiography)", optionB: "Indirect flat panel (CsI/a-Si)", optionC: "Film-screen", optionD: "Direct conversion (a-Se)", correctAnswer: "B", rationale: "Indirect flat panel detectors using CsI scintillators generally have the highest DQE (~65-75%) due to the structured CsI crystal that minimizes light spread.", category: "Image Production", topic: "Digital Imaging", difficulty: 3, country: "usa", exam: "arrt" },
  { question: "In digital imaging, window level controls:", optionA: "Image contrast", optionB: "Image brightness (density)", optionC: "Spatial resolution", optionD: "Image noise", correctAnswer: "B", rationale: "Window level controls the brightness/density of the displayed image. Increasing window level makes the image brighter; decreasing makes it darker.", category: "Image Production", topic: "Digital Image Processing", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "In digital imaging, window width controls:", optionA: "Image brightness", optionB: "Image contrast", optionC: "Spatial resolution", optionD: "Magnification", correctAnswer: "B", rationale: "Window width controls contrast. A narrow window displays fewer gray levels (high contrast). A wide window displays more gray levels (low contrast).", category: "Image Production", topic: "Digital Image Processing", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "The histogram in digital radiography represents:", optionA: "Patient dose", optionB: "The distribution of pixel values in the image", optionC: "Equipment calibration data", optionD: "Spatial resolution", correctAnswer: "B", rationale: "The histogram is a graphical representation of the number of pixels at each gray level value, used to determine optimal image display parameters.", category: "Image Production", topic: "Digital Image Processing", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Histogram analysis errors can occur when:", optionA: "The technique is perfect", optionB: "Extraneous objects, collimation, or prostheses are in the field", optionC: "The patient is perfectly centered", optionD: "The correct body part is selected", correctAnswer: "B", rationale: "Histogram analysis errors occur when foreign objects, excessive collimation edges, prostheses, or other artifacts alter the expected pixel value distribution.", category: "Image Production", topic: "Digital Image Processing", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Pixel size determines:", optionA: "Image contrast", optionB: "Spatial resolution (smaller pixels = better resolution)", optionC: "Image brightness", optionD: "Patient dose", correctAnswer: "B", rationale: "Pixel size directly affects spatial resolution. Smaller pixels provide better spatial resolution (more detail) but generate larger file sizes.", category: "Image Production", topic: "Digital Imaging", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "The matrix size of a digital image:", optionA: "Has no effect on image quality", optionB: "Determines the number of pixels (larger matrix = more pixels = better resolution)", optionC: "Only affects file size", optionD: "Controls image contrast", correctAnswer: "B", rationale: "A larger matrix (e.g., 3072 × 3072 vs 2048 × 2048) contains more pixels, resulting in smaller pixel size and improved spatial resolution.", category: "Image Production", topic: "Digital Imaging", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Bit depth in digital imaging determines:", optionA: "Spatial resolution", optionB: "The number of possible gray levels (contrast resolution)", optionC: "File size only", optionD: "Patient dose", correctAnswer: "B", rationale: "Bit depth determines the number of possible gray levels. A 12-bit system provides 2¹² = 4096 gray levels. Higher bit depth = better contrast resolution.", category: "Image Production", topic: "Digital Imaging", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Edge enhancement in digital image processing:", optionA: "Reduces image noise", optionB: "Increases visibility of interfaces/borders between structures", optionC: "Increases exposure latitude", optionD: "Reduces spatial resolution", correctAnswer: "B", rationale: "Edge enhancement (high-pass filtering/unsharp mask) increases the visibility of interfaces between different tissue densities, improving perceived sharpness.", category: "Image Production", topic: "Digital Image Processing", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Smoothing (noise reduction) in digital processing:", optionA: "Improves spatial resolution", optionB: "Reduces quantum noise but may decrease spatial resolution", optionC: "Increases noise", optionD: "Increases contrast", correctAnswer: "B", rationale: "Smoothing algorithms reduce quantum noise by averaging adjacent pixel values, but this can decrease spatial resolution (blur fine detail).", category: "Image Production", topic: "Digital Image Processing", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Image noise in digital radiography is primarily caused by:", optionA: "High kVp", optionB: "Insufficient mAs (quantum mottle)", optionC: "Excessive filtration", optionD: "Large focal spot", correctAnswer: "B", rationale: "Quantum mottle (noise) is caused by an insufficient number of X-ray photons reaching the detector. It is the primary source of noise in digital radiography.", category: "Image Production", topic: "Image Quality", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "To reduce quantum noise in a digital image, the technologist should:", optionA: "Decrease mAs", optionB: "Increase mAs", optionC: "Decrease kVp", optionD: "Decrease SID", correctAnswer: "B", rationale: "Increasing mAs increases the number of photons reaching the detector, reducing quantum mottle/noise. However, this increases patient dose.", category: "Image Production", topic: "Image Quality", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "The signal-to-noise ratio (SNR) in digital imaging:", optionA: "Should be minimized", optionB: "Should be maximized for optimal image quality", optionC: "Is unrelated to image quality", optionD: "Is only relevant in CT", correctAnswer: "B", rationale: "A high SNR means the useful signal is much greater than the noise, producing a higher quality image. SNR is proportional to the square root of mAs.", category: "Image Production", topic: "Image Quality", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Contrast resolution in digital imaging refers to:", optionA: "The ability to distinguish fine detail", optionB: "The ability to distinguish between tissues with similar densities", optionC: "The sharpness of edges", optionD: "The size of the pixel", correctAnswer: "B", rationale: "Contrast resolution (low-contrast detectability) is the ability to distinguish between tissues with small differences in density, superior in digital imaging compared to film.", category: "Image Production", topic: "Image Quality", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "Dynamic range (exposure latitude) in digital imaging compared to film-screen:", optionA: "Is narrower", optionB: "Is much wider", optionC: "Is the same", optionD: "Does not exist", correctAnswer: "B", rationale: "Digital imaging has a much wider dynamic range than film-screen, accepting a broader range of exposures and producing diagnostic images. This is both an advantage and a risk (dose creep).", category: "Image Production", topic: "Digital Imaging", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "Exposure index (EI) values that are too high indicate:", optionA: "Underexposure", optionB: "Overexposure", optionC: "Optimal exposure", optionD: "Equipment malfunction", correctAnswer: "B", rationale: "High EI values indicate overexposure (too much radiation reached the detector). The image may look acceptable but patient dose is unnecessarily high.", category: "Image Production", topic: "Digital Imaging", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "The automatic exposure control (AEC) device terminates exposure when:", optionA: "A preset time is reached", optionB: "A preset amount of radiation has been detected by the ionization chamber", optionC: "The technologist presses the button", optionD: "The mAs reaches a preset value", correctAnswer: "B", rationale: "AEC uses ionization chambers positioned behind the patient that terminate the exposure when a predetermined amount of radiation (optimal receptor exposure) has been detected.", category: "Image Production", topic: "Automatic Exposure Control", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "The AEC ionization chamber(s) should be positioned:", optionA: "At the edges of the anatomy", optionB: "Under the area of clinical interest (thickest or most important anatomy)", optionC: "Always in the center position only", optionD: "Outside the collimated field", correctAnswer: "B", rationale: "The selected AEC chamber(s) must be positioned under the area of clinical interest to ensure proper exposure of the most important anatomy.", category: "Image Production", topic: "Automatic Exposure Control", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "When using AEC, the technologist must select:", optionA: "Only the mAs", optionB: "The correct kVp, chamber selection, and backup time", optionC: "Only the exposure time", optionD: "Only the mAs and SID", correctAnswer: "B", rationale: "With AEC, the technologist selects kVp (controls contrast), the appropriate ionization chamber(s), and sets a backup time (safety cutoff).", category: "Image Production", topic: "Automatic Exposure Control", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "If the center AEC chamber is selected for a PA chest radiograph, the resulting image will be:", optionA: "Properly exposed", optionB: "Overexposed (too dark/too much density) because the spine attenuates more", optionC: "Underexposed", optionD: "No different than other chamber selections", correctAnswer: "B", rationale: "The center chamber is behind the spine (dense structure), causing AEC to deliver more radiation to penetrate it, resulting in overexposure of the lung fields.", category: "Image Production", topic: "Automatic Exposure Control", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "For a PA chest radiograph with AEC, the correct chamber selection is:", optionA: "Center chamber only", optionB: "Both lateral (outside) chambers", optionC: "All three chambers", optionD: "The right chamber only", correctAnswer: "B", rationale: "Both lateral chambers should be selected for PA chest to measure exposure through the lung fields, providing optimal lung density.", category: "Image Production", topic: "Automatic Exposure Control", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "The minimum response time of an AEC is important because:", optionA: "It determines maximum technique", optionB: "If the exposure needed is less than the minimum response time, overexposure results", optionC: "It affects spatial resolution", optionD: "It controls kVp", correctAnswer: "B", rationale: "If the patient is very thin or technique too high, the AEC may not terminate quickly enough (limited by its minimum response time), resulting in overexposure.", category: "Image Production", topic: "Automatic Exposure Control", difficulty: 3, country: "usa", exam: "arrt" },
  { question: "Scatter radiation reaching the image receptor:", optionA: "Improves contrast", optionB: "Adds unwanted fog, reducing contrast", optionC: "Improves spatial resolution", optionD: "Has no effect on image quality", correctAnswer: "B", rationale: "Scatter radiation adds uniform fog to the image, reducing contrast (the difference between adjacent densities) and degrading overall image quality.", category: "Image Production", topic: "Image Quality", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "Scatter production increases with:", optionA: "Smaller field size and lower kVp", optionB: "Larger field size, higher kVp, and increased patient thickness", optionC: "Smaller patient size", optionD: "Lower mAs", correctAnswer: "B", rationale: "Scatter increases with larger field size (more tissue irradiated), higher kVp (more Compton interactions), and greater patient thickness.", category: "Image Production", topic: "Image Quality", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "A grid ratio of 12:1 compared to 8:1:", optionA: "Absorbs less scatter", optionB: "Absorbs more scatter but requires higher mAs (more patient dose)", optionC: "Has no effect on scatter absorption", optionD: "Requires less mAs", correctAnswer: "B", rationale: "Higher grid ratios absorb more scatter (better cleanup) but also absorb more primary radiation, requiring increased mAs and higher patient dose.", category: "Image Production", topic: "Grids", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "The grid frequency refers to:", optionA: "The number of grid lines per inch or centimeter", optionB: "How often the grid oscillates", optionC: "The thickness of the lead strips", optionD: "The grid ratio", correctAnswer: "A", rationale: "Grid frequency is the number of lead strips per inch or centimeter. Higher frequency grids have thinner, more closely spaced strips and produce less visible grid lines.", category: "Image Production", topic: "Grids", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "A Potter-Bucky diaphragm (Bucky) is a:", optionA: "Stationary grid", optionB: "Moving grid that oscillates during exposure to blur grid lines", optionC: "Type of collimator", optionD: "Lead apron", correctAnswer: "B", rationale: "A Potter-Bucky diaphragm is a moving grid mechanism that oscillates the grid during exposure, blurring the grid lines so they are not visible on the image.", category: "Image Production", topic: "Grids", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "Grids are typically used when the body part thickness exceeds:", optionA: "5 cm", optionB: "10 cm", optionC: "15 cm", optionD: "20 cm", correctAnswer: "B", rationale: "Grids are generally used when the body part exceeds 10 cm in thickness and/or kVp exceeds 60-70, as scatter production becomes significant.", category: "Image Production", topic: "Grids", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "A focused grid is designed for use at a specific:", optionA: "kVp range", optionB: "SID range (convergent point/focal distance)", optionC: "Patient size", optionD: "mAs range", correctAnswer: "B", rationale: "Focused grids have lead strips angled to converge at a specific distance (focal distance/convergent line). Using outside this range causes grid cutoff.", category: "Image Production", topic: "Grids", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Off-center grid cutoff appears as:", optionA: "One side lighter than the other", optionB: "Uniform density reduction across the entire image", optionC: "Central lighter area", optionD: "Grid lines visible on one side only", correctAnswer: "B", rationale: "Off-center grid cutoff (grid not centered to the central ray) produces uniform density reduction across the entire image.", category: "Image Production", topic: "Grids", difficulty: 3, country: "usa", exam: "arrt" },
  { question: "Off-level (tilted) grid cutoff appears as:", optionA: "Uniform density reduction across the entire image", optionB: "One side lighter than the other", optionC: "Central lighter area with darkening at edges", optionD: "Grid lines visible everywhere", correctAnswer: "A", rationale: "Off-level (tilted) grid cutoff causes uniform density reduction because the central ray is not perpendicular to the grid along the length of the strips.", category: "Image Production", topic: "Grids", difficulty: 3, country: "usa", exam: "arrt" },
  { question: "An upside-down focused grid produces:", optionA: "Normal image appearance", optionB: "Acceptable density in the center with severe cutoff at the periphery", optionC: "Uniform overexposure", optionD: "One side darker than the other", correctAnswer: "B", rationale: "An upside-down focused grid allows primary beam through the center but progressively cuts off toward the edges as strip angles diverge from the beam direction.", category: "Image Production", topic: "Grids", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "The grid conversion factor (Bucky factor) represents:", optionA: "The grid ratio", optionB: "The factor by which mAs must be increased when using a grid", optionC: "The grid frequency", optionD: "The interspace material", correctAnswer: "B", rationale: "The grid conversion factor (Bucky factor) indicates how much mAs must be increased when using a grid to maintain image density. For 8:1 grid, it's approximately 4.", category: "Image Production", topic: "Grids", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "The focal spot size affects:", optionA: "Image contrast", optionB: "Recorded detail/spatial resolution", optionC: "Image density only", optionD: "Scatter production", correctAnswer: "B", rationale: "Smaller focal spots produce less geometric unsharpness (penumbra), resulting in better recorded detail/spatial resolution.", category: "Image Production", topic: "Image Quality", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "The line-focus principle states that:", optionA: "SID and SOD determine magnification", optionB: "The effective focal spot is smaller than the actual focal spot due to the anode angle", optionC: "Beam filtration improves quality", optionD: "Collimation reduces scatter", correctAnswer: "B", rationale: "The line-focus principle describes how angling the anode target makes the effective (projected) focal spot smaller than the actual focal spot, improving resolution.", category: "Image Production", topic: "X-ray Tube Design", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "A steeper anode angle produces:", optionA: "Larger effective focal spot", optionB: "Smaller effective focal spot but limits field coverage", optionC: "More uniform beam intensity", optionD: "Greater heat capacity", correctAnswer: "B", rationale: "A steeper (smaller) anode angle produces a smaller effective focal spot but limits the maximum field size at a given SID. Typical angles are 7-17 degrees.", category: "Image Production", topic: "X-ray Tube Design", difficulty: 3, country: "usa", exam: "arrt" },
  { question: "Increasing OID (object-to-image distance):", optionA: "Decreases magnification", optionB: "Increases magnification and geometric unsharpness", optionC: "Improves spatial resolution", optionD: "Decreases patient dose", correctAnswer: "B", rationale: "Increasing OID increases magnification and geometric unsharpness (blur) because the object is farther from the image receptor.", category: "Image Production", topic: "Image Quality", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "Increasing SID:", optionA: "Increases magnification", optionB: "Decreases magnification and improves spatial resolution", optionC: "Has no effect on image quality", optionD: "Increases geometric blur", correctAnswer: "B", rationale: "Increasing SID makes the beam more parallel, reducing magnification and geometric unsharpness, thus improving spatial resolution.", category: "Image Production", topic: "Image Quality", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "Shape distortion in radiography includes:", optionA: "Magnification only", optionB: "Elongation and foreshortening", optionC: "Quantum mottle", optionD: "Histogram errors", correctAnswer: "B", rationale: "Shape distortion includes elongation (angled CR or angled part) and foreshortening (angled part with perpendicular CR), both misrepresenting the true shape.", category: "Image Production", topic: "Image Quality", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Elongation occurs when:", optionA: "The tube or IR is angled along the length of the structure", optionB: "The part is perpendicular to the beam", optionC: "No angulation is used", optionD: "The SID is too long", correctAnswer: "A", rationale: "Elongation occurs when the tube or IR is angled, causing the projected image to appear longer than the actual structure.", category: "Image Production", topic: "Image Quality", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Foreshortening occurs when:", optionA: "The central ray is angled", optionB: "The object is angled/not parallel to the IR", optionC: "The SID is increased", optionD: "The OID is decreased", correctAnswer: "B", rationale: "Foreshortening occurs when the object is not parallel to the IR (angled object), causing the projected image to appear shorter than actual.", category: "Image Production", topic: "Image Quality", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Motion blur is best controlled by:", optionA: "Increasing mAs", optionB: "Using the shortest possible exposure time", optionC: "Using a large focal spot", optionD: "Increasing SID", correctAnswer: "B", rationale: "Motion unsharpness is minimized by using the shortest possible exposure time. High mA with short time maintains mAs while reducing motion blur.", category: "Image Production", topic: "Image Quality", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "The modulation transfer function (MTF) describes:", optionA: "Patient dose efficiency", optionB: "The ability of an imaging system to reproduce object contrast at different spatial frequencies", optionC: "Exposure latitude", optionD: "Noise levels", correctAnswer: "B", rationale: "MTF measures how well the imaging system transfers contrast from the object to the image across different spatial frequencies. MTF = 1 is perfect; MTF = 0 is no transfer.", category: "Image Production", topic: "Image Quality", difficulty: 3, country: "usa", exam: "arrt" },
  { question: "In digital imaging, aliasing (Moiré pattern) can occur when:", optionA: "The patient moves", optionB: "An object with a periodic pattern matches the sampling frequency (Nyquist limit)", optionC: "Too much scatter is present", optionD: "The kVp is too high", correctAnswer: "B", rationale: "Aliasing occurs when the spatial frequency of an object exceeds the Nyquist frequency (half the sampling frequency), producing Moiré artifacts.", category: "Image Production", topic: "Digital Imaging", difficulty: 3, country: "usa", exam: "arrt" },
  { question: "The Nyquist frequency determines:", optionA: "Maximum mAs", optionB: "The maximum spatial frequency that can be recorded without aliasing", optionC: "Image contrast", optionD: "Exposure latitude", correctAnswer: "B", rationale: "The Nyquist frequency = 1/(2 × pixel pitch). It represents the maximum spatial frequency that can be accurately sampled without aliasing.", category: "Image Production", topic: "Digital Imaging", difficulty: 3, country: "usa", exam: "arrt" },
  { question: "Subject contrast depends on:", optionA: "mAs setting", optionB: "Tissue thickness, density, atomic number, and kVp", optionC: "SID only", optionD: "Focal spot size", correctAnswer: "B", rationale: "Subject contrast is determined by the differential absorption of X-rays by different tissues, influenced by tissue thickness, density, effective atomic number, and beam energy (kVp).", category: "Image Production", topic: "Image Quality", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Automatic rescaling in digital radiography can mask:", optionA: "Motion artifacts", optionB: "Exposure errors (making over/underexposed images appear acceptable)", optionC: "Positioning errors", optionD: "Equipment malfunction", correctAnswer: "B", rationale: "Automatic rescaling adjusts the displayed image to appear optimal regardless of exposure, potentially masking overexposure (increased patient dose) or underexposure (increased noise).", category: "Image Production", topic: "Digital Imaging", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "DICOM stands for:", optionA: "Digital Imaging and Computer Operations in Medicine", optionB: "Digital Imaging and Communications in Medicine", optionC: "Digital Image Contrast Optimization Method", optionD: "Diagnostic Imaging Computer Output Management", correctAnswer: "B", rationale: "DICOM (Digital Imaging and Communications in Medicine) is the standard for storing, transmitting, and managing medical images across different systems.", category: "Image Production", topic: "Digital Imaging Standards", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "PACS stands for:", optionA: "Patient Access and Communication System", optionB: "Picture Archiving and Communication System", optionC: "Portable Advanced Computer System", optionD: "Programmed Automatic Contrast System", correctAnswer: "B", rationale: "PACS (Picture Archiving and Communication System) stores, retrieves, manages, distributes, and displays medical images digitally.", category: "Image Production", topic: "Digital Imaging Standards", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "The exposure indicator on a Carestream CR system that indicates overexposure would show:", optionA: "High EI number", optionB: "Low EI number", optionC: "EI = 0", optionD: "No change", correctAnswer: "A", rationale: "On Carestream/Kodak CR systems, higher EI values indicate more exposure. Fuji uses S-number where lower values indicate more exposure.", category: "Image Production", topic: "Digital Imaging", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "On a Fuji CR system, a low S-number indicates:", optionA: "Underexposure", optionB: "Overexposure", optionC: "Optimal exposure", optionD: "Equipment error", correctAnswer: "B", rationale: "Fuji's S-number is inversely related to exposure: lower S = more exposure (overexposure), higher S = less exposure (underexposure).", category: "Image Production", topic: "Digital Imaging", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Look-up tables (LUTs) in digital imaging are used to:", optionA: "Store patient data", optionB: "Map raw pixel values to displayed gray levels for optimal visualization", optionC: "Calculate patient dose", optionD: "Compress image files", correctAnswer: "B", rationale: "LUTs map the raw detector data to appropriate display values, optimizing brightness and contrast for the specific body part and projection.", category: "Image Production", topic: "Digital Image Processing", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Image artifacts in digital radiography can be caused by:", optionA: "Only patient motion", optionB: "Dead pixels, ghosting, grid artifacts, software errors, and hardware failures", optionC: "Only overexposure", optionD: "Only underexposure", correctAnswer: "B", rationale: "Digital artifacts include dead/stuck pixels, ghost images (incomplete erasure), grid artifacts (aliasing), software processing errors, and detector calibration failures.", category: "Image Production", topic: "Digital Imaging Artifacts", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Ghosting artifact in CR occurs when:", optionA: "The patient moves", optionB: "The phosphor plate is not fully erased before reuse", optionC: "The laser is misaligned", optionD: "The kVp is too low", correctAnswer: "B", rationale: "Ghosting occurs when residual image data remains on the PSP plate from a previous exposure due to incomplete erasure during the erase cycle.", category: "Image Production", topic: "Digital Imaging Artifacts", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "The backup timer on AEC is set to:", optionA: "Determine the normal exposure", optionB: "Prevent excessive exposure if AEC malfunctions", optionC: "Control kVp", optionD: "Set the focal spot size", correctAnswer: "B", rationale: "The backup timer is a safety mechanism that terminates exposure at a preset maximum mAs or time to prevent excessive patient dose if the AEC fails to terminate.", category: "Image Production", topic: "Automatic Exposure Control", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "When imaging a smaller patient with AEC, the density control should be adjusted:", optionA: "To +2", optionB: "To the minus (-) direction to reduce exposure", optionC: "No adjustment needed; AEC compensates automatically", optionD: "To +1", correctAnswer: "C", rationale: "AEC automatically compensates for patient size, producing consistent receptor exposure regardless of patient thickness. Manual density adjustments are for specific clinical needs.", category: "Image Production", topic: "Automatic Exposure Control", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "The reciprocity law in radiography states that:", optionA: "kVp and mAs are interchangeable", optionB: "Any combination of mA and time producing the same mAs will produce the same exposure", optionC: "SID and mAs are proportional", optionD: "Grid ratio and mAs are inversely related", correctAnswer: "B", rationale: "The reciprocity law states that the same mAs produces the same exposure regardless of the mA-time combination (e.g., 100 mA × 0.1s = 200 mA × 0.05s = 10 mAs).", category: "Image Production", topic: "Technical Factors", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "When converting from non-grid to 12:1 grid technique, the mAs should be increased by a factor of:", optionA: "2", optionB: "3", optionC: "5", optionD: "8", correctAnswer: "C", rationale: "The approximate grid conversion factors are: no grid=1, 5:1=2, 6:1=3, 8:1=4, 12:1=5, 16:1=6. For 12:1 grid, multiply mAs by 5.", category: "Image Production", topic: "Grids", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Quantum mottle appears as:", optionA: "Black artifacts on the image", optionB: "A grainy or mottled (salt-and-pepper) appearance", optionC: "Grid lines", optionD: "White spots", correctAnswer: "B", rationale: "Quantum mottle appears as a grainy, mottled (salt-and-pepper) appearance caused by statistical fluctuation in the number of X-ray photons detected.", category: "Image Production", topic: "Image Quality", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "The primary purpose of the X-ray tube collimator is to:", optionA: "Filter low-energy photons", optionB: "Restrict the X-ray beam to the area of interest", optionC: "Control beam energy", optionD: "Reduce exposure time", correctAnswer: "B", rationale: "The collimator restricts (collimates) the X-ray beam to the area of clinical interest, reducing patient dose and scatter radiation production.", category: "Image Production", topic: "Beam Restriction", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "Subtraction technique in digital imaging is used to:", optionA: "Remove scatter", optionB: "Remove overlying structures to visualize contrast-filled vessels", optionC: "Reduce noise", optionD: "Increase spatial resolution", correctAnswer: "B", rationale: "Digital subtraction (e.g., DSA) subtracts a pre-contrast mask image from post-contrast images, eliminating bone and soft tissue to visualize contrast-filled vessels.", category: "Image Production", topic: "Digital Image Processing", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "The source-to-image distance (SID) affects image density according to:", optionA: "The reciprocity law", optionB: "The inverse square law", optionC: "The 15% rule", optionD: "Beer's law", correctAnswer: "B", rationale: "The inverse square law governs how radiation intensity changes with distance. As SID increases, intensity at the IR decreases by the square of the distance ratio.", category: "Image Production", topic: "Technical Factors", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "If mAs is doubled, the image density will:", optionA: "Decrease by half", optionB: "Double (increase proportionally)", optionC: "Remain unchanged", optionD: "Quadruple", correctAnswer: "B", rationale: "Image density is directly proportional to mAs. Doubling mAs doubles the number of photons reaching the receptor, doubling the density/exposure.", category: "Image Production", topic: "Technical Factors", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "Absorption efficiency of a digital detector refers to:", optionA: "The percentage of incident X-rays that are absorbed by the detector", optionB: "The percentage of absorbed X-rays converted to signal", optionC: "The total DQE", optionD: "The noise level", correctAnswer: "A", rationale: "Absorption efficiency is the fraction of incident X-ray photons absorbed by the detector. Higher absorption efficiency means more signal and less dose needed.", category: "Image Production", topic: "Digital Imaging", difficulty: 3, country: "usa", exam: "arrt" },
  { question: "Conversion efficiency of a digital detector refers to:", optionA: "The percentage of X-rays absorbed", optionB: "How well absorbed X-ray energy is converted into a useful signal", optionC: "The speed of readout", optionD: "Image compression ratio", correctAnswer: "B", rationale: "Conversion efficiency measures how effectively the absorbed X-ray energy is converted into an electrical or light signal for image formation.", category: "Image Production", topic: "Digital Imaging", difficulty: 3, country: "usa", exam: "arrt" },
  { question: "Magnification radiography requires:", optionA: "Large focal spot and short SID", optionB: "Fractional (small) focal spot and increased OID", optionC: "Large focal spot and decreased OID", optionD: "Standard technique", correctAnswer: "B", rationale: "Intentional magnification requires a fractional focal spot (0.1-0.3 mm) to maintain resolution and increased OID to produce controlled magnification.", category: "Image Production", topic: "Special Techniques", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "The tube rating chart is used to determine:", optionA: "Patient dose", optionB: "Whether a selected technique will exceed the tube heat loading capacity", optionC: "Image quality", optionD: "Grid selection", correctAnswer: "B", rationale: "The tube rating chart shows the maximum safe combinations of kVp, mA, and time for a specific focal spot size, preventing tube damage from overheating.", category: "Image Production", topic: "X-ray Tube Design", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "The anode cooling chart shows:", optionA: "Patient dose over time", optionB: "The rate at which the anode dissipates heat", optionC: "Image quality parameters", optionD: "Exposure technique selection", correctAnswer: "B", rationale: "The anode cooling chart displays the relationship between heat units stored and cooling time, indicating how long to wait between exposures to prevent tube damage.", category: "Image Production", topic: "X-ray Tube Design", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Heat units (HU) for a single-phase generator are calculated as:", optionA: "kVp × mAs", optionB: "kVp × mA × time", optionC: "mAs × SID", optionD: "kVp × mAs × 1.41", correctAnswer: "B", rationale: "For single-phase: HU = kVp × mA × time. For three-phase/high-frequency: HU = kVp × mA × time × 1.35 (3-phase 6-pulse) or × 1.41 (3-phase 12-pulse/high-frequency).", category: "Image Production", topic: "X-ray Tube Design", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Beam hardening refers to:", optionA: "Increasing beam quantity", optionB: "Selective absorption of lower-energy photons, increasing average beam energy", optionC: "Decreasing beam penetration", optionD: "Reducing beam intensity", correctAnswer: "B", rationale: "Beam hardening occurs as filtration preferentially removes lower-energy photons, increasing the average energy (and HVL) of the remaining beam.", category: "Image Production", topic: "X-ray Beam Characteristics", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Added filtration affects the X-ray beam by:", optionA: "Increasing beam quantity and decreasing quality", optionB: "Decreasing beam quantity and increasing quality (average energy)", optionC: "Having no effect on beam characteristics", optionD: "Increasing both quantity and quality equally", correctAnswer: "B", rationale: "Added filtration removes low-energy photons (decreasing quantity/intensity) while increasing the average energy (quality) of the remaining beam.", category: "Image Production", topic: "X-ray Beam Characteristics", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "The primary beam refers to:", optionA: "Scatter radiation from the patient", optionB: "The X-ray beam that exits the tube and reaches the patient", optionC: "Leakage radiation", optionD: "Remnant radiation", correctAnswer: "B", rationale: "The primary beam is the X-ray beam that exits the tube housing through the collimator opening and is directed toward the patient.", category: "Image Production", topic: "X-ray Beam Characteristics", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "Remnant radiation (exit radiation) is:", optionA: "The primary beam before reaching the patient", optionB: "The radiation that passes through the patient and reaches the image receptor", optionC: "Scatter radiation only", optionD: "Leakage radiation", correctAnswer: "B", rationale: "Remnant (exit) radiation is what passes through the patient, consisting of transmitted primary photons and scattered photons. It forms the image.", category: "Image Production", topic: "X-ray Beam Characteristics", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "JPEG compression is an example of:", optionA: "Lossless compression", optionB: "Lossy compression (some data is permanently lost)", optionC: "No compression", optionD: "Reversible compression", correctAnswer: "B", rationale: "JPEG is a lossy compression method that permanently removes some image data to achieve smaller file sizes. It should not be used for primary diagnostic images.", category: "Image Production", topic: "Digital Imaging Standards", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "JPEG 2000 lossless compression:", optionA: "Permanently removes image data", optionB: "Preserves all original image data and allows complete reconstruction", optionC: "Is not used in medical imaging", optionD: "Reduces image quality significantly", correctAnswer: "B", rationale: "JPEG 2000 lossless compression preserves all image data, allowing exact reconstruction. It typically achieves 2:1 to 3:1 compression ratios.", category: "Image Production", topic: "Digital Imaging Standards", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Contrast resolution in digital imaging is superior to film-screen because:", optionA: "Pixels are larger", optionB: "Digital detectors capture a wider range of gray values and can apply post-processing", optionC: "Digital images have higher spatial resolution", optionD: "Film has better contrast", correctAnswer: "B", rationale: "Digital detectors have wider dynamic range, higher bit depth, and post-processing capabilities that allow visualization of subtle density differences not visible on film.", category: "Image Production", topic: "Digital Imaging", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Image stitching in digital radiography is used for:", optionA: "Correcting exposure errors", optionB: "Combining multiple images into a single long image (e.g., full spine or full leg)", optionC: "Reducing noise", optionD: "Improving contrast", correctAnswer: "B", rationale: "Image stitching combines multiple overlapping exposures into a single composite image for long-length views such as full spine scoliosis series or full leg length studies.", category: "Image Production", topic: "Digital Image Processing", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Proper collimation on a digital image should show:", optionA: "No collimation borders", optionB: "Clear collimation borders demonstrating field limitation to the anatomy of interest", optionC: "Collimation at the edge of the IR only", optionD: "Maximum field size at all times", correctAnswer: "B", rationale: "Proper collimation should be visible on the image, demonstrating that the field was limited to the anatomy of interest, reducing dose and improving image quality.", category: "Image Production", topic: "Beam Restriction", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "When using an image receptor that is larger than the anatomy being imaged, the technologist should:", optionA: "Use maximum field size", optionB: "Collimate to the anatomy regardless of IR size", optionC: "Increase mAs to fill the IR", optionD: "Use no grid", correctAnswer: "B", rationale: "Regardless of IR size, collimation must be limited to the anatomy of interest to reduce patient dose and scatter radiation.", category: "Image Production", topic: "Beam Restriction", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "The unsharp mask technique in digital processing:", optionA: "Removes all noise", optionB: "Enhances edges by subtracting a blurred version from the original", optionC: "Reduces contrast", optionD: "Compresses the image", correctAnswer: "B", rationale: "Unsharp masking creates a blurred copy of the image, subtracts it from the original, and adds the difference back, enhancing edge details.", category: "Image Production", topic: "Digital Image Processing", difficulty: 3, country: "usa", exam: "arrt" },
  { question: "In the DICOM standard, the 'grayscale standard display function' ensures:", optionA: "All monitors display color images", optionB: "Consistent image appearance across different display devices", optionC: "Maximum brightness", optionD: "Minimum contrast", correctAnswer: "B", rationale: "The GSDF (Grayscale Standard Display Function) ensures perceptually linear display across different monitors, so images appear consistent regardless of the viewing station.", category: "Image Production", topic: "Digital Imaging Standards", difficulty: 3, country: "usa", exam: "arrt" },
  { question: "Image receptor sensitivity (speed) in CR is analogous to:", optionA: "Grid ratio", optionB: "Film-screen speed class", optionC: "Focal spot size", optionD: "SID", correctAnswer: "B", rationale: "CR sensitivity is analogous to film-screen speed class. Higher sensitivity requires less exposure but may produce more noise. Typical sensitivity values are 200, 400, etc.", category: "Image Production", topic: "Digital Imaging", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "The purpose of image annotation in digital radiography includes:", optionA: "Improving spatial resolution", optionB: "Adding patient ID, date, markers, and examination information to the image", optionC: "Reducing patient dose", optionD: "Compressing the image file", correctAnswer: "B", rationale: "Image annotation electronically adds essential information (patient ID, date, laterality markers, facility name) to the digital image for identification and legal purposes.", category: "Image Production", topic: "Digital Imaging", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "Proper anatomical marker placement requires:", optionA: "Markers can be placed electronically after the exposure", optionB: "Lead markers (R or L) must be placed on the IR before exposure within the collimated field", optionC: "Markers are optional", optionD: "Markers should be placed outside the collimated field", correctAnswer: "B", rationale: "Lead anatomical markers must be placed on the IR before exposure, within the collimated field, and not obscuring anatomy. Electronic markers alone are insufficient.", category: "Image Production", topic: "Image Quality", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "The quality assurance test for screen-contact in a CR cassette involves:", optionA: "Exposing a wire mesh tool and evaluating for areas of poor contact", optionB: "Measuring radiation output", optionC: "Evaluating kVp accuracy", optionD: "Testing generator reproducibility", correctAnswer: "A", rationale: "A wire mesh (screen-contact) test evaluates for areas of poor phosphor-to-cassette contact, which appear as blurred areas on the image.", category: "Image Production", topic: "Quality Control", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "The Hurter and Driffield (H&D) curve for film relates:", optionA: "kVp to mAs", optionB: "Exposure to optical density (characteristic curve)", optionC: "SID to magnification", optionD: "Grid ratio to contrast", correctAnswer: "B", rationale: "The H&D (characteristic/sensitometric) curve plots the relationship between log relative exposure and optical density for film, showing speed, latitude, and contrast characteristics.", category: "Image Production", topic: "Film Radiography", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "In a technique chart, the primary factor adjusted for changes in body part thickness is:", optionA: "kVp", optionB: "mAs (using the 4 cm rule or similar approach)", optionC: "SID", optionD: "Focal spot", correctAnswer: "B", rationale: "Technique charts typically adjust mAs for body part thickness changes (e.g., increasing mAs by 30-50% for every 4-5 cm increase in thickness) while kVp remains relatively constant.", category: "Image Production", topic: "Technique Charts", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "The three types of technique charts are:", optionA: "Manual, automatic, and digital", optionB: "Fixed kVp, variable kVp, and automatic", optionC: "Small, medium, and large", optionD: "Pediatric, adult, and geriatric", correctAnswer: "B", rationale: "The three types are: fixed kVp (kVp constant, mAs varies with thickness), variable kVp (mAs constant, kVp varies), and automatic (AEC-based).", category: "Image Production", topic: "Technique Charts", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Beam restriction (collimation) affects image quality by:", optionA: "Increasing scatter production", optionB: "Reducing scatter production and improving contrast", optionC: "Having no effect on contrast", optionD: "Decreasing spatial resolution", correctAnswer: "B", rationale: "Proper collimation reduces the volume of tissue irradiated, decreasing scatter production and improving image contrast.", category: "Image Production", topic: "Beam Restriction", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "The size of the X-ray field is determined by:", optionA: "SID only", optionB: "Collimator opening and SID", optionC: "kVp setting", optionD: "mAs setting", correctAnswer: "B", rationale: "Field size depends on the collimator opening (adjustable lead shutters) and the SID. A larger SID produces a larger field for the same collimator opening.", category: "Image Production", topic: "Beam Restriction", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "The primary advantage of using high mA with short exposure time is:", optionA: "Reduced patient dose", optionB: "Reduced motion blur while maintaining the same mAs", optionC: "Improved contrast", optionD: "Better spatial resolution", correctAnswer: "B", rationale: "High mA with short time maintains the same mAs (and image density) while reducing motion unsharpness — critical for pediatric and trauma imaging.", category: "Image Production", topic: "Technical Factors", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "The exposure maintenance formula (direct square law) is:", optionA: "mAs₂ = mAs₁ × (SID₂/SID₁)", optionB: "mAs₂ = mAs₁ × (SID₂/SID₁)²", optionC: "mAs₂ = mAs₁ × (SID₁/SID₂)²", optionD: "mAs₂ = mAs₁ × (SID₂/SID₁)³", correctAnswer: "B", rationale: "The direct square law maintains image density when SID changes: new mAs = old mAs × (new SID / old SID)².", category: "Image Production", topic: "Technical Factors", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "At a SID of 40 inches using 20 mAs, what mAs is needed at 72 inches SID?", optionA: "36 mAs", optionB: "65 mAs", optionC: "11 mAs", optionD: "40 mAs", correctAnswer: "B", rationale: "mAs₂ = 20 × (72/40)² = 20 × 3.24 = 64.8 ≈ 65 mAs.", category: "Image Production", topic: "Technical Factors", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "The intensity of radiation at 2 meters from the source is 40 mR. What is the intensity at 4 meters?", optionA: "20 mR", optionB: "10 mR", optionC: "5 mR", optionD: "80 mR", correctAnswer: "B", rationale: "Using the inverse square law: I₂ = 40 × (2/4)² = 40 × 0.25 = 10 mR.", category: "Image Production", topic: "Technical Factors", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "For a properly exposed lateral cervical spine, the technique should produce adequate density of:", optionA: "The vertebral bodies and posterior elements", optionB: "The soft tissues only", optionC: "The mandible", optionD: "The shoulders", correctAnswer: "A", rationale: "A properly exposed lateral cervical spine shows the vertebral bodies, disc spaces, posterior elements (spinous processes, facets), and prevertebral soft tissues.", category: "Image Production", topic: "Technique Selection", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "For chest radiography, the preferred kVp range is:", optionA: "50-60 kVp", optionB: "70-80 kVp", optionC: "110-125 kVp", optionD: "130-150 kVp", correctAnswer: "C", rationale: "High kVp (110-125) is used for chest radiography to produce long-scale contrast, visualizing both lung markings and mediastinal structures.", category: "Image Production", topic: "Technique Selection", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "For extremity radiography, the typical kVp range is:", optionA: "50-70 kVp", optionB: "80-90 kVp", optionC: "100-120 kVp", optionD: "130+ kVp", correctAnswer: "A", rationale: "Extremities use low kVp (50-70) to produce high contrast for optimal visualization of bony detail.", category: "Image Production", topic: "Technique Selection", difficulty: 1, country: "usa", exam: "arrt" },
  { question: "Image post-processing that cannot be corrected digitally includes:", optionA: "Brightness and contrast", optionB: "Motion blur, positioning errors, and artifacts caused by foreign objects", optionC: "Window width and level", optionD: "Edge enhancement", correctAnswer: "B", rationale: "While brightness, contrast, and edge enhancement can be adjusted digitally, motion blur, positioning errors, and physical artifacts in the field cannot be corrected by post-processing.", category: "Image Production", topic: "Digital Image Processing", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "The term 'saturation' in digital imaging refers to:", optionA: "Optimal exposure", optionB: "The detector receiving maximum signal capacity, causing loss of detail in overexposed areas", optionC: "Underexposure", optionD: "Normal detector operation", correctAnswer: "B", rationale: "Saturation occurs when the detector receives more radiation than it can record, resulting in completely white areas with no diagnostic information.", category: "Image Production", topic: "Digital Imaging", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "Flat-fielding (gain calibration) in digital detectors corrects for:", optionA: "Patient motion", optionB: "Non-uniform detector response (pixel-to-pixel sensitivity variations)", optionC: "kVp inaccuracies", optionD: "Timer errors", correctAnswer: "B", rationale: "Flat-field calibration corrects for inherent differences in sensitivity between individual detector elements (pixels), ensuring uniform image response.", category: "Image Production", topic: "Digital Imaging", difficulty: 3, country: "usa", exam: "arrt" },
  { question: "The detective quantum efficiency of CR compared to flat panel DR is:", optionA: "Higher", optionB: "Lower", optionC: "Equal", optionD: "Variable", correctAnswer: "B", rationale: "CR systems typically have lower DQE (15-30%) compared to flat panel DR systems (45-75%), meaning more dose is needed for equivalent image quality.", category: "Image Production", topic: "Digital Imaging", difficulty: 2, country: "usa", exam: "arrt" },
  { question: "The exposure latitude of digital imaging systems:", optionA: "Is narrower than film-screen", optionB: "Is much wider than film-screen", optionC: "Is the same as film-screen", optionD: "Does not exist", correctAnswer: "B", rationale: "Digital systems have exposure latitude of approximately 10,000:1 compared to film-screen at approximately 100:1, allowing acceptable images across a much wider range of exposures.", category: "Image Production", topic: "Digital Imaging", difficulty: 1, country: "usa", exam: "arrt" },
];

